"use client";

import { useRef, useEffect, useState } from "react";
import { Box, IconButton, Paper, Stack, Typography } from "@mui/material";
import { alpha } from "@mui/material/styles";
import TuneRoundedIcon from "@mui/icons-material/TuneRounded";

/**
 * @mention and #folder floating autocomplete dropdown menu.
 * Viewport-aware: flips above cursor when near bottom of screen.
 */
export default function TokenMenu({
  tokenMenu,
  activeTokenSuggestions,
  applyTokenSuggestion,
  closeTokenMenu,
  onOpenCustomization,
}) {
  const menuRef = useRef(null);
  const [flipAbove, setFlipAbove] = useState(false);

  useEffect(() => {
    if (!tokenMenu.visible || !menuRef.current) {
      setFlipAbove(false);
      return;
    }
    const menuHeight = menuRef.current.offsetHeight;
    const viewportHeight = window.innerHeight;
    const MARGIN = 12;
    setFlipAbove(tokenMenu.y + menuHeight + MARGIN > viewportHeight);
  }, [tokenMenu.visible, tokenMenu.y, tokenMenu.x, activeTokenSuggestions.length]);

  const menuHeight = menuRef.current?.offsetHeight || 0;
  const computedY = flipAbove
    ? Math.max(8, tokenMenu.y - 10 - 22 - menuHeight - 8)
    : tokenMenu.y;
  const computedX = Math.min(tokenMenu.x, Math.max(0, typeof window !== "undefined" ? window.innerWidth - 350 : 1000));

  return (
    <Box
      ref={menuRef}
      sx={{
        position: "fixed",
        left: computedX,
        top: computedY,
        opacity: tokenMenu.visible ? 1 : 0,
        transform: tokenMenu.visible ? "translateY(0)" : "translateY(6px)",
        transition: "opacity 140ms ease, transform 140ms ease",
        pointerEvents: tokenMenu.visible ? "auto" : "none",
        zIndex: 1600,
        maxHeight: "calc(100vh - 24px)",
        overflowY: "auto",
      }}
    >
      <Paper
        elevation={8}
        sx={{
          minWidth: 280,
          maxWidth: 340,
          borderRadius: 3,
          overflow: "hidden",
          border: "1px solid #ddd0c0",
          bgcolor: "#fdf8f1",
          boxShadow: "0 16px 34px rgba(58, 46, 34, 0.18)",
        }}
      >
        <Box
          sx={{
            px: 1.4,
            py: 1,
            borderBottom: "1px solid #ebe1d4",
            background: "linear-gradient(180deg, #fbf3e8 0%, #f7ecde 100%)",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
          }}
        >
          <Typography sx={{ fontSize: 11, fontWeight: 800, color: "#6a5a49", letterSpacing: "0.08em", textTransform: "uppercase" }}>
            {tokenMenu.tokenType === "mention" ? "People" : "Folders"}
          </Typography>
          <Stack direction="row" spacing={0.5} alignItems="center">
            {onOpenCustomization && (
              <IconButton
                size="small"
                onMouseDown={(e) => { e.preventDefault(); e.stopPropagation(); closeTokenMenu(); onOpenCustomization(); }}
                sx={{ width: 22, height: 22, color: "#6a5a49", "&:hover": { bgcolor: alpha("#c4956a", 0.12) } }}
              >
                <TuneRoundedIcon sx={{ fontSize: 14 }} />
              </IconButton>
            )}
            <Typography sx={{ color: "#6a5a49", fontSize: 14, fontWeight: 800, lineHeight: 1 }}>
              {tokenMenu.tokenType === "mention" ? "@" : "#"}
            </Typography>
          </Stack>
        </Box>
        <Stack spacing={0} sx={{ py: 0.5, maxHeight: "50vh", overflowY: "auto" }}>
          {activeTokenSuggestions.map((item, index) => (
            <Box
              key={item.id}
              onMouseDown={(e) => {
                e.preventDefault();
                applyTokenSuggestion(item);
              }}
              sx={{
                px: tokenMenu.tokenType === "mention" ? 1.6 : 1.4,
                py: tokenMenu.tokenType === "mention" ? 1.15 : 1,
                cursor: "pointer",
                bgcolor: index === tokenMenu.selectedIndex ? alpha("#c4956a", 0.12) : "transparent",
                transition: "background-color 120ms ease",
                "&:hover": { bgcolor: alpha("#c4956a", 0.12) },
              }}
            >
              {tokenMenu.tokenType === "mention" ? (
                <Stack direction="row" spacing={1.1} alignItems="center">
                  <Box
                    sx={{
                      width: 40,
                      height: 40,
                      borderRadius: "50%",
                      display: "grid",
                      placeItems: "center",
                      position: "relative",
                      background: item.__isCreate
                        ? "transparent"
                        : item.__isHint
                          ? alpha("#c4956a", 0.12)
                          : `linear-gradient(135deg, ${item.accent} 0%, ${alpha(item.accent, 0.68)} 100%)`,
                      border: item.__isCreate ? "2px dashed #c4956a" : item.__isHint ? "1px dashed #c4956a" : "none",
                      color: item.__isCreate || item.__isHint ? "#c4956a" : "#fffdf8",
                      fontSize: item.__isCreate ? 20 : item.__isHint ? 12 : 13,
                      fontWeight: 800,
                      letterSpacing: "0.04em",
                      boxShadow: item.__isCreate || item.__isHint ? "none" : `0 10px 20px ${alpha(item.accent, 0.26)}, inset 0 1px 0 rgba(255,255,255,0.28)`,
                      flexShrink: 0,
                      "&::after": item.__isCreate || item.__isHint ? {} : {
                        content: '""',
                        position: "absolute",
                        right: 2,
                        bottom: 2,
                        width: 9,
                        height: 9,
                        borderRadius: "50%",
                        background: "#22c55e",
                        boxShadow: "0 0 0 2px rgba(253, 248, 241, 0.96)",
                      },
                    }}
                  >
                    {item.__isHint
                      ? "@"
                      : item.__isCreate
                        ? "+"
                        : item.name.split(" ").map((part) => part[0]).join("").slice(0, 2).toUpperCase()}
                  </Box>
                  <Box sx={{ minWidth: 0 }}>
                    <Typography sx={{ fontSize: 14, fontWeight: 800, color: item.__isCreate || item.__isHint ? "#8b5e3c" : "#2f2721", lineHeight: 1.15, letterSpacing: "-0.02em" }}>
                      {item.__isHint ? item.name : item.__isCreate ? `Create @${item.name}` : item.name}
                    </Typography>
                    {!item.__isCreate && !item.__isHint && (
                      <Stack direction="row" spacing={0.7} alignItems="center" sx={{ mt: 0.25, flexWrap: "wrap" }}>
                        <Typography sx={{ fontSize: 11, fontWeight: 800, color: item.accent, px: 0.7, py: 0.22, borderRadius: 999, bgcolor: alpha(item.accent, 0.1), lineHeight: 1, letterSpacing: "0.01em" }}>
                          @{item.handle}
                        </Typography>
                        <Typography sx={{ fontSize: 11.5, color: "#7b6c5c", lineHeight: 1.2 }}>{item.role}</Typography>
                      </Stack>
                    )}
                    {item.__isCreate && <Typography sx={{ fontSize: 11.5, color: "#7b6c5c", lineHeight: 1.2 }}>Add as new person & insert mention</Typography>}
                    {item.__isHint && <Typography sx={{ fontSize: 11.5, color: "#7b6c5c", lineHeight: 1.2 }}>Start typing after @ to create or search a person</Typography>}
                  </Box>
                </Stack>
              ) : (
                <>
                  <Typography sx={{ fontSize: 13, fontWeight: 700, color: item.__isCreate || item.__isHint ? "#8b5e3c" : "#352f29" }}>
                    {item.__isHint ? item.name : item.__isCreate ? `+ Create #${item.path}` : item.path}
                  </Typography>
                  <Typography sx={{ fontSize: 11.5, color: "#7b6c5c" }}>
                    {item.__isHint ? "Start typing after # to create or search a folder" : item.__isCreate ? "Add as new folder & insert reference" : item.description}
                  </Typography>
                </>
              )}
            </Box>
          ))}
        </Stack>
      </Paper>
    </Box>
  );
}

"use client";

import { useCallback } from "react";
import { richTokenBoundarySelector } from "./constants";
import { uncheckedIconSvg } from "../shared";

/**
 * Hook for the editor's keyDown handler.
 * Handles slash/token menu navigation, list/table/todo escape, and rich-token boundary management.
 *
 * @param {Object} params
 * @param {Object}   params.slashMenu
 * @param {Function} params.setSlashMenu
 * @param {Array}    params.activeSuggestions
 * @param {Function} params.applySlashSuggestion
 * @param {Function} params.closeSlashMenu
 * @param {Object}   params.tokenMenu
 * @param {Function} params.setTokenMenu
 * @param {Array}    params.activeTokenSuggestions
 * @param {Function} params.applyTokenSuggestion
 * @param {Function} params.closeTokenMenu
 * @param {Function} params.onEditorInput
 */
export default function useEditorKeyDown({
  slashMenu,
  setSlashMenu,
  activeSuggestions,
  applySlashSuggestion,
  closeSlashMenu,
  tokenMenu,
  setTokenMenu,
  activeTokenSuggestions,
  applyTokenSuggestion,
  closeTokenMenu,
  onEditorInput,
}) {
  const handleEditorKeyDown = useCallback(
    (event) => {
      if (event.ctrlKey || event.metaKey || event.altKey) return;

      /* ── Slash menu keyboard navigation ── */
      if (slashMenu.visible && activeSuggestions.length > 0) {
        if (event.key === "ArrowDown") {
          event.preventDefault();
          setSlashMenu((prev) => ({ ...prev, selectedIndex: (prev.selectedIndex + 1) % activeSuggestions.length }));
          return;
        }
        if (event.key === "ArrowUp") {
          event.preventDefault();
          setSlashMenu((prev) => ({ ...prev, selectedIndex: (prev.selectedIndex - 1 + activeSuggestions.length) % activeSuggestions.length }));
          return;
        }
        if (event.key === "Escape") {
          event.preventDefault();
          closeSlashMenu();
          return;
        }
        if (event.key === "Enter" || event.key === "Tab") {
          event.preventDefault();
          applySlashSuggestion(activeSuggestions[slashMenu.selectedIndex] || activeSuggestions[0]);
          return;
        }
      }

      /* ── Token menu keyboard navigation ── */
      if (tokenMenu.visible && activeTokenSuggestions.length > 0) {
        if (event.key === "ArrowDown") {
          event.preventDefault();
          setTokenMenu((prev) => ({ ...prev, selectedIndex: (prev.selectedIndex + 1) % activeTokenSuggestions.length }));
          return;
        }
        if (event.key === "ArrowUp") {
          event.preventDefault();
          setTokenMenu((prev) => ({ ...prev, selectedIndex: (prev.selectedIndex - 1 + activeTokenSuggestions.length) % activeTokenSuggestions.length }));
          return;
        }
        if (event.key === "Escape") {
          event.preventDefault();
          closeTokenMenu();
          return;
        }
        if (event.key === "Enter" || event.key === "Tab") {
          event.preventDefault();
          applyTokenSuggestion(activeTokenSuggestions[tokenMenu.selectedIndex] || activeTokenSuggestions[0]);
          return;
        }
      }

      const sel = window.getSelection();
      if (!sel || sel.rangeCount === 0) return;

      /* ── If selection is active, let browser collapse it natively on arrow keys.
             We just return early so our rich-token boundary code doesn't fire. ── */
      if (!sel.isCollapsed) {
        const key = event.key;
        if (key === "ArrowLeft" || key === "ArrowRight") {
          // Don't preventDefault — let the browser collapse naturally (Left→start, Right→end).
          // Return so our rich-token-boundary logic below doesn't also run.
          return;
        }
        // For any other key with an active selection, let the browser handle it.
        return;
      }

      const node = sel.anchorNode;
      if (!node) return;

      const isEnter = event.key === "Enter";

      /* ── Escape standard lists (ul/ol) on Enter if empty ── */
      if (isEnter) {
        const liNode = node.nodeType === 3 ? node.parentElement : node;
        const li = liNode?.closest?.("li");
        if (li) {
          const list = li.closest("ul, ol");
          const isEmpty = !li.textContent.trim() || li.textContent === "\u200B";

          if (isEmpty) {
            event.preventDefault();
            const p = document.createElement("p");
            p.innerHTML = "<br>";
            if (list && list.parentNode) {
              list.parentNode.insertBefore(p, list.nextSibling);
            }
            li.parentNode.removeChild(li);
            if (list && list.children.length === 0 && list.parentNode) {
              list.parentNode.removeChild(list);
            }
            const newRange = document.createRange();
            newRange.setStart(p, 0);
            newRange.collapse(true);
            sel.removeAllRanges();
            sel.addRange(newRange);
            if (onEditorInput) onEditorInput();
            return;
          }
        }
      }

      /* ── Escape Table on Enter ── */
      if (isEnter) {
        const cellNode = node.nodeType === 3 ? node.parentElement : node;
        const cell = cellNode?.closest?.("td, th");
        if (cell) {
          event.preventDefault();
          const tr = cell.closest("tr");
          const table = cell.closest("table");
          const tbody = tr.parentNode;
          const isRowEmpty = Array.from(tr.cells).every((c) => c.textContent.trim() === "" && !c.querySelector("img"));

          if (isRowEmpty) {
            const p = document.createElement("p");
            p.innerHTML = "<br>";
            table.parentNode.insertBefore(p, table.nextSibling);
            tr.parentNode.removeChild(tr);
            if (tbody.children.length === 0) {
              table.parentNode.removeChild(table);
            }
            const newRange = document.createRange();
            newRange.setStart(p, 0);
            newRange.collapse(true);
            sel.removeAllRanges();
            sel.addRange(newRange);
          } else {
            const isLastColumn = cell === tr.lastElementChild;
            if (isLastColumn) {
              const newTr = document.createElement("tr");
              const numCols = tr.cells.length;
              for (let i = 0; i < numCols; i++) {
                const newTd = document.createElement("td");
                newTd.style.border = "1px solid #d9cab7";
                newTd.style.padding = "6px";
                newTd.style.minWidth = "50px";
                newTd.innerHTML = "<br>";
                newTr.appendChild(newTd);
              }
              tr.parentNode.insertBefore(newTr, tr.nextSibling);
              const newRange = document.createRange();
              newRange.setStart(newTr.firstElementChild, 0);
              newRange.collapse(true);
              sel.removeAllRanges();
              sel.addRange(newRange);
            } else {
              document.execCommand("insertLineBreak", false, null);
            }
          }
          if (onEditorInput) onEditorInput();
          return;
        }
      }

      /* ── Escape Todo list on Enter ── */
      if (isEnter) {
        const todoNode = node.nodeType === 3 ? node.parentElement : node;
        const todoDiv = todoNode?.closest?.("[data-todo]");
        if (todoDiv) {
          event.preventDefault();
          const textContainer = todoDiv.querySelector("div[style*='flex: 1']");
          const textContent = textContainer ? textContainer.innerText.trim() : "";

          if (!textContent) {
            const p = document.createElement("p");
            p.innerHTML = "<br>";
            todoDiv.parentNode.insertBefore(p, todoDiv.nextSibling);
            todoDiv.parentNode.removeChild(todoDiv);
            const newRange = document.createRange();
            newRange.setStart(p, 0);
            newRange.collapse(true);
            sel.removeAllRanges();
            sel.addRange(newRange);
          } else {
            const newTodoHtml = `<div data-todo="false" style="display: flex; align-items: flex-start; gap: 8px; margin: 4px 0;"><span data-todo-checkbox="true" style="cursor: pointer; color: #8b5e3c; display: flex; align-items: center; justify-content: center; user-select: none;" contenteditable="false">${uncheckedIconSvg}</span><div style="flex: 1; outline: none; min-width: 50px;"><br></div></div>`;
            todoDiv.insertAdjacentHTML("afterend", newTodoHtml);
            const newTodo = todoDiv.nextElementSibling;
            const newTextContainer = newTodo.querySelector("div[style*='flex: 1']");
            const newRange = document.createRange();
            newRange.setStart(newTextContainer, 0);
            newRange.collapse(true);
            sel.removeAllRanges();
            sel.addRange(newRange);
          }
          if (onEditorInput) onEditorInput();
          return;
        }
      }

      /* ── Rich token boundary management ── */
      const el = node.nodeType === 3 ? node.parentElement : node;
      const span = el?.closest?.(richTokenBoundarySelector);
      if (!span) return;

      const isPrintable = event.key.length === 1;
      const isArrowRight = event.key === "ArrowRight";
      const isArrowLeft = event.key === "ArrowLeft";

      if (!isPrintable && !isEnter && !isArrowRight && !isArrowLeft) return;

      const spanRange = document.createRange();
      spanRange.selectNodeContents(span);
      const cursorRange = sel.getRangeAt(0);

      const isAtStart = cursorRange.compareBoundaryPoints(Range.START_TO_START, spanRange) <= 0;
      const isAtEnd = cursorRange.compareBoundaryPoints(Range.START_TO_END, spanRange) >= 0;

      if (isArrowRight && isAtEnd) {
        event.preventDefault();
        const newRange = document.createRange();
        if (span.nextSibling) {
          if (span.nextSibling.nodeType === 3) {
            newRange.setStart(span.nextSibling, 0);
          } else {
            newRange.setStartAfter(span);
          }
        } else {
          const zws = document.createTextNode("\u200B");
          span.parentNode.appendChild(zws);
          newRange.setStart(zws, 1);
        }
        newRange.collapse(true);
        sel.removeAllRanges();
        sel.addRange(newRange);
        return;
      }

      if (isArrowLeft && isAtStart) {
        event.preventDefault();
        const newRange = document.createRange();
        if (span.previousSibling) {
          if (span.previousSibling.nodeType === 3) {
            newRange.setStart(span.previousSibling, span.previousSibling.length);
          } else {
            newRange.setStartBefore(span);
          }
        } else {
          const zws = document.createTextNode("\u200B");
          span.parentNode.insertBefore(zws, span);
          newRange.setStart(zws, 0);
        }
        newRange.collapse(true);
        sel.removeAllRanges();
        sel.addRange(newRange);
        return;
      }

      if (!isAtEnd && !isAtStart) return;
      if (isArrowRight || isArrowLeft) return;

      event.preventDefault();

      if (isEnter) {
        const newRange = document.createRange();
        if (isAtEnd) {
          newRange.setStartAfter(span);
        } else {
          newRange.setStartBefore(span);
        }
        newRange.collapse(true);
        sel.removeAllRanges();
        sel.addRange(newRange);
        document.execCommand("insertLineBreak", false, null);
        if (onEditorInput) onEditorInput();
        return;
      }

      const content = event.key;
      const textNode = document.createTextNode(content);

      if (isAtEnd) {
        if (span.nextSibling) {
          span.parentNode.insertBefore(textNode, span.nextSibling);
        } else {
          span.parentNode.appendChild(textNode);
        }
      } else {
        span.parentNode.insertBefore(textNode, span);
      }

      const newRange = document.createRange();
      newRange.setStart(textNode, textNode.length);
      newRange.collapse(true);
      sel.removeAllRanges();
      sel.addRange(newRange);

      if (onEditorInput) onEditorInput();
    },
    [
      activeSuggestions,
      activeTokenSuggestions,
      applySlashSuggestion,
      applyTokenSuggestion,
      closeSlashMenu,
      closeTokenMenu,
      onEditorInput,
      slashMenu.selectedIndex,
      slashMenu.visible,
      tokenMenu.selectedIndex,
      tokenMenu.visible,
    ]
  );

  return handleEditorKeyDown;
}

"use client";

import { useState, useCallback } from "react";
import { uncheckedIconSvg } from "../shared";

const TOP_LEVEL_COMMANDS = [
  {
    id: "command-note",
    kind: "command",
    command: "note",
    label: "Sticky Note",
    description: "Create or open a pinned note",
  },
  {
    id: "command-date",
    kind: "command",
    command: "date",
    label: "Date",
    description: "Insert today's date or pick one",
  },
  {
    id: "command-time",
    kind: "command",
    command: "time",
    label: "Time",
    description: "Insert the current time",
  },
  {
    id: "command-todo",
    kind: "command",
    command: "todo",
    label: "Todo",
    description: "Add checkable tasks",
  },
  {
    id: "command-map",
    kind: "command",
    command: "map",
    label: "Location",
    description: "Pin a place on the map",
  },
];

/**
 * Hook for slash command logic (/note, /date, /time, /todo, /map).
 *
 * @param {Object} params
 * @param {Object|null} params.activeNote
 * @param {Array}  params.stickyNotes
 * @param {Function} params.onEditorInput
 * @param {Function} params.onAddStickyNote
 * @param {Function} params.onOpenStickyNote
 */
export default function useSlashCommands({
  activeNote,
  stickyNotes = [],
  onEditorInput,
  onAddStickyNote,
  onOpenStickyNote,
}) {
  const [slashMenu, setSlashMenu] = useState({
    visible: false,
    x: 0,
    y: 0,
    query: "",
    selectedIndex: 0,
    token: "",
    command: "",
    argument: "",
    title: "Commands",
  });

  const getDateSuggestions = useCallback((query) => {
    const today = new Date();

    const getFormatsForDate = (date) => [
      date.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" }),
      date.toLocaleDateString("en-US", { weekday: "long", month: "long", day: "numeric", year: "numeric" }),
      `${date.getMonth() + 1}/${date.getDate()}/${date.getFullYear()}`,
      `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`,
    ];

    let targetDate = new Date(today);
    let dateLabelPrefix = "";

    const lowerQuery = query.toLowerCase();
    if (lowerQuery.includes("tom")) {
      targetDate.setDate(today.getDate() + 1);
      dateLabelPrefix = "Tomorrow";
    } else if (lowerQuery.includes("yes")) {
      targetDate.setDate(today.getDate() - 1);
      dateLabelPrefix = "Yesterday";
    } else {
      let match = lowerQuery.match(/(\d+)\s*d(?:ay(?:s)?)?\s*ago/);
      if (match) {
        targetDate.setDate(today.getDate() - parseInt(match[1], 10));
        dateLabelPrefix = `${match[1]} Days Ago`;
      } else {
        match = lowerQuery.match(/in\s*(\d+)\s*d(?:ay(?:s)?)?/);
        if (match) {
          targetDate.setDate(today.getDate() + parseInt(match[1], 10));
          dateLabelPrefix = `In ${match[1]} Days`;
        } else if (!lowerQuery.trim()) {
          dateLabelPrefix = "Today";
        }
      }
    }

    return getFormatsForDate(targetDate).map((format, index) => ({
      id: `date-${index}`,
      kind: "date",
      label: format,
      description: dateLabelPrefix ? `${dateLabelPrefix} (${format})` : format,
      value: format,
    }));
  }, []);

  const getTimeSuggestions = useCallback(() => {
    const now = new Date();
    const formats = [
      now.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" }),
      now.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit", second: "2-digit" }),
      now.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", hour12: false }),
      now.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false }),
      `${now.toLocaleDateString("en-US", { month: "short", day: "numeric", year: "numeric" })} ${now.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" })}`,
    ];

    return formats.map((format, index) => ({
      id: `time-${index}`,
      kind: "time",
      label: format,
      description: `Current time (${format})`,
      value: format,
    }));
  }, []);

  const getSlashCommandContext = useCallback(() => {
    const sel = window.getSelection();
    if (!sel || !sel.isCollapsed || sel.rangeCount === 0) return null;

    const node = sel.anchorNode;
    if (!node || node.nodeType !== 3) return null;

    const beforeText = node.textContent?.slice(0, sel.anchorOffset) || "";
    const match = beforeText.match(/(?:^|\s)(\/[a-z]*(?:\s+[^\n\r]*)?)$/i);
    if (!match) return null;

    const caretRange = sel.getRangeAt(0).cloneRange();
    caretRange.collapse(true);
    const rect = caretRange.getBoundingClientRect();
    const token = match[1];
    const startIndex = beforeText.lastIndexOf(token);
    const tokenBody = token.slice(1);
    const firstSpaceIndex = tokenBody.indexOf(" ");
    const command = (firstSpaceIndex === -1 ? tokenBody : tokenBody.slice(0, firstSpaceIndex)).toLowerCase();
    const argument = firstSpaceIndex === -1 ? "" : tokenBody.slice(firstSpaceIndex + 1);

    return {
      textNode: node,
      token,
      startIndex,
      endIndex: startIndex + token.length,
      rect,
      command,
      argument,
    };
  }, []);

  const getCommandSuggestions = useCallback((commandQuery) => {
    const cleanQuery = commandQuery.trim().toLowerCase();
    return TOP_LEVEL_COMMANDS.filter((item) => !cleanQuery || item.command.startsWith(cleanQuery));
  }, []);

  const getActiveSuggestions = useCallback(() => {
    const command = slashMenu.command;
    const argument = slashMenu.argument.trim();

    if (!command) {
      return {
        title: "Commands",
        items: getCommandSuggestions(""),
      };
    }

    const exactCommand = TOP_LEVEL_COMMANDS.find((item) => item.command === command);
    if (!exactCommand) {
      return {
        title: "Commands",
        items: getCommandSuggestions(command),
      };
    }

    if (command === "note") {
      return {
        title: "Sticky Notes",
        items: [
          { id: "create-sticky-note", kind: "create", label: "Create sticky note", description: "Open a new sticky note for this page" },
          ...stickyNotes
            .filter((note) => note.noteId === activeNote?.id)
            .map((note) => ({
              id: note.id,
              kind: "existing",
              label: note.title?.trim() || "Untitled sticky note",
              description: "Open existing sticky note",
            })),
        ],
      };
    }

    if (command === "date") {
      return {
        title: "Date Formats",
        items: getDateSuggestions(argument),
      };
    }

    if (command === "time") {
      return {
        title: "Time Formats",
        items: getTimeSuggestions(),
      };
    }

    if (command === "todo") {
      return {
        title: "Todo Options",
        items: [
          { id: "todo-1", kind: "todo", label: "Insert 1 Todo", description: "Add a single todo checkbox", count: 1 },
          { id: "todo-3", kind: "todo", label: "Insert 3 Todos", description: "Add three todo checkboxes", count: 3 },
          { id: "todo-5", kind: "todo", label: "Insert 5 Todos", description: "Add five todo checkboxes", count: 5 },
        ],
      };
    }

    if (command === "map") {
      return {
        title: "Location",
        items: argument
          ? [{ id: "map-pin", kind: "map", label: `📍 ${argument}`, description: `Insert location: ${argument}`, value: argument }]
          : [{ id: "map-hint", kind: "map", label: "📍 Insert Location", description: "Type a place after /map", value: "" }],
      };
    }

    return {
      title: "Commands",
      items: getCommandSuggestions(command),
    };
  }, [activeNote?.id, getCommandSuggestions, getDateSuggestions, getTimeSuggestions, slashMenu.argument, slashMenu.command, stickyNotes]);

  const { title: suggestionTitle, items: activeSuggestions } = getActiveSuggestions();

  const closeSlashMenu = useCallback(() => {
    setSlashMenu((prev) => (
      prev.visible
        ? { ...prev, visible: false, selectedIndex: 0, command: "", argument: "", title: "Commands" }
        : prev
    ));
  }, []);

  const refreshSlashMenu = useCallback(() => {
    const context = getSlashCommandContext();
    if (!context) {
      closeSlashMenu();
      return;
    }

    const isTopLevel = !context.command;
    const commandMatches = TOP_LEVEL_COMMANDS.some((item) => item.command.startsWith(context.command));
    if (!isTopLevel && !commandMatches) {
      closeSlashMenu();
      return;
    }

    setSlashMenu((prev) => ({
      visible: true,
      x: context.rect.left,
      y: context.rect.bottom + 10,
      query: context.token.toLowerCase(),
      token: context.token,
      command: context.command,
      argument: context.argument,
      title: suggestionTitle,
      selectedIndex: prev.token === context.token ? prev.selectedIndex : 0,
    }));
  }, [closeSlashMenu, getSlashCommandContext, suggestionTitle]);

  const replaceSlashToken = useCallback((context, nextValue, keepMenuOpen = false) => {
    if (!context?.textNode) return;

    const currentText = context.textNode.textContent || "";
    const newTextContent = `${currentText.slice(0, context.startIndex)}${nextValue}${currentText.slice(context.endIndex)}`;
    context.textNode.textContent = newTextContent;

    const nextRange = document.createRange();
    const nextSelection = window.getSelection();
    const cursorOffset = context.startIndex + nextValue.length;

    nextRange.setStart(context.textNode, Math.min(cursorOffset, context.textNode.textContent.length));
    nextRange.collapse(true);
    nextSelection?.removeAllRanges();
    nextSelection?.addRange(nextRange);

    if (onEditorInput) onEditorInput();

    if (keepMenuOpen) {
      window.requestAnimationFrame(() => {
        refreshSlashMenu();
      });
      return;
    }

    closeSlashMenu();
  }, [closeSlashMenu, onEditorInput, refreshSlashMenu]);

  const applySlashSuggestion = useCallback((item) => {
    const context = getSlashCommandContext();

    if (item.kind === "command") {
      replaceSlashToken(context, `/${item.command} `, true);
      return;
    }

    if (item.kind === "date" || item.kind === "time") {
      replaceSlashToken(context, item.value);
      return;
    }

    if (context?.textNode) {
      replaceSlashToken(context, "");
    } else {
      closeSlashMenu();
      if (onEditorInput) onEditorInput();
    }

    if (item.kind === "todo") {
      const count = item.count || 1;
      const singleTodo = `<div data-todo="false" style="display: flex; align-items: flex-start; gap: 8px; margin: 4px 0;"><span data-todo-checkbox="true" style="cursor: pointer; color: #8b5e3c; display: flex; align-items: center; justify-content: center; user-select: none;" contenteditable="false">${uncheckedIconSvg}</span><div style="flex: 1; outline: none; min-width: 50px;"><br></div></div>`;
      document.execCommand("insertHTML", false, singleTodo.repeat(count));
      if (onEditorInput) onEditorInput();
      return;
    }

    if (item.kind === "map" && item.value) {
      const mapUrl = `https://www.google.com/maps/search/${encodeURIComponent(item.value)}`;
      const mapHtml = `<a href="${mapUrl}" target="_blank" rel="noopener noreferrer" data-location="${item.value.replace(/"/g, "&quot;")}" style="display:inline-flex;align-items:center;gap:0.3em;vertical-align:middle;border-radius:999px;padding:0.18em 0.6em;margin:0 0.1em;background:rgba(255,248,240,0.96);border:1px solid rgba(139,94,60,0.22);box-shadow:0 2px 8px rgba(92,61,46,0.1);color:#3e2f24;text-decoration:none;line-height:1.4;font-size:0.88em;font-weight:600;cursor:pointer;">📍 ${item.value}</a>&nbsp;`;
      document.execCommand("insertHTML", false, mapHtml);
      if (onEditorInput) onEditorInput();
      return;
    }

    if (item.kind === "create") {
      onAddStickyNote?.();
      return;
    }

    if (item.kind === "existing") {
      onOpenStickyNote?.(item.id);
    }
  }, [closeSlashMenu, getSlashCommandContext, onAddStickyNote, onEditorInput, onOpenStickyNote, refreshSlashMenu, replaceSlashToken]);

  return {
    slashMenu: { ...slashMenu, title: suggestionTitle },
    setSlashMenu,
    activeSuggestions,
    getDateSuggestions,
    getTimeSuggestions,
    closeSlashMenu,
    refreshSlashMenu,
    applySlashSuggestion,
  };
}

